-- Install:  exaplus -f dist/mariadb-compat.sql   (installs 8 of 9 scripts)
--     or:   python install.py ...                (installs all 9 — recommended)
--
-- exaplus 25.2.6 has a client-side parser bug: after the FIRST
-- --/ ... / PREPROCESSOR block, subsequent --/ markers no longer enter
-- script-body mode and the next script's body is dropped. This bundle
-- orders the production MARIA_PREPROCESSOR before MARIA_PREPROCESSOR_DEBUG
-- so production survives the exaplus path; DEBUG is dev-only and
-- install.py installs both reliably.

CREATE SCHEMA IF NOT EXISTS UTIL;

